from dataclasses import dataclass, field

@dataclass
class State:
    ws_num: int = 0
    ws_count: int = 0
    ws_idx: int = 0
    ws_i: int = 0
    ws_n: int = 0
    ws_total: int = 0
    ws_sum: int = 0
    sub: int = 0
    other_fields: dict = field(default_factory=dict)

    def __getitem__(self, key: str):
        return getattr(self, key, self.other_fields.get(key, ''))

    def __setitem__(self, key: str, value):
        if hasattr(self, key):
            setattr(self, key, value)
        else:
            self.other_fields[key] = value

state = State()

